import{_ as a,o,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"FAQ & Solución de Problemas","description":"","frontmatter":{},"headers":[],"relativePath":"es/faq.md","filePath":"es/faq.md"}'),t={name:"es/faq.md"};function l(n,e,r,c,d,m){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="faq-solucion-de-problemas" tabindex="-1"><i class="ph ph-question"></i> FAQ &amp; Solución de Problemas <a class="header-anchor" href="#faq-solucion-de-problemas" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ &amp; Solución de Problemas&quot;">​</a></h1><p>Esta sección recopila respuestas a las preguntas más frecuentes y soluciones a problemas típicos encontrados durante la optimización de WebGL.</p><h2 id="instalacion-y-escena-de-demostracion" tabindex="-1"><i class="ph ph-package"></i> Instalación y Escena de Demostración <a class="header-anchor" href="#instalacion-y-escena-de-demostracion" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; Instalación y Escena de Demostración&quot;">​</a></h2><details class="details custom-block"><summary>P: ¡Abrí la escena de demostración, pero todos los materiales y objetos son de color rosa!</summary><p><strong>R:</strong> Tu proyecto usa URP, mientras que la escena de demostración está configurada por defecto para BiRP. Simplemente desempaqueta el paquete ubicado en <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code>. Los shaders se actualizarán automáticamente.</p></details><details class="details custom-block"><summary>P: Instalé el plugin, pero visualmente no cambia absolutamente nada en el juego.</summary><p><strong>R:</strong> Revisa la siguiente lista de verificación:</p><ul><li>¿Está habilitado el plugin en Project Settings? ¿Se agregaron y activaron los Scalers?</li><li>¿Los gráficos de Unity están configurados inicialmente al máximo? El plugin no tiene nada que reducir si la configuración ya es baja.</li><li>Tal vez el dispositivo maneja la carga perfectamente y los FPS son estables. Agrega el prefab <code>Dashboard</code> a la escena para observar las decisiones en curso del Indexer.</li><li>Si todo está configurado correctamente pero no hay efecto, contáctanos y te ayudaremos con la solución del problema.</li></ul></details><h2 id="resolucion-e-interfaz-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> Resolución e Interfaz (UI) <a class="header-anchor" href="#resolucion-e-interfaz-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; Resolución e Interfaz (UI)&quot;">​</a></h2><details class="details custom-block"><summary>P: La resolución no cambia (Resolution Scaler inactivo).</summary><p><strong>R:</strong> Las dos razones más comunes son:</p><ol><li>Si usas <strong>BiRP</strong> y el modo <code>RenderTextureScaling</code>: revisa el array <code>Target Tags</code> en la configuración del Scaler. Si la cámara de tu juego tiene un nombre diferente (no <code>MainCamera</code>), debes insertar esa etiqueta. De lo contrario, el plugin no podrá localizarla.</li><li>El modo <code>NativeBrowserScaling</code> solo opera en una build de WebGL renderizada final. No hace nada dentro del Unity Editor.</li></ol></details><details class="details custom-block"><summary>P: Cuando bajan los FPS, ¡mi interfaz de usuario también se distorsiona/desenfoca!</summary><p><strong>R:</strong> Confirma que en BiRP tienes seleccionado <code>RenderTextureScaling</code>. El Canvas en sí debe estar configurado en el modo <code>Screen Space - Overlay</code> (o usar una cámara dedicada solo para la interfaz de usuario).</p></details><details class="details custom-block"><summary>P: Los botones estándar de la interfaz de usuario funcionan bien, pero mis clics del ratón (raycasts personalizados) en objetos 3D fallan.</summary><p><strong>R:</strong> Los eventos estándar de EventSystem son reparados de manera perfecta por nuestro componente <code>WebScaledPhysicsRaycaster</code>. Sin embargo, si llamas a raycasts manuales por código (<code>Camera.ScreenPointToRay()</code>), fallarán la posición del clic porque la resolución de la pantalla no coincide con la renderizada. Con este fin, aplica el método de nuestro plugin: <code>WebRaycasterUtility.TryComputeScaledRay()</code>.</p></details><h2 id="metricas-y-comportamiento-del-sistema" tabindex="-1"><i class="ph ph-chart-line-up"></i> Métricas y Comportamiento del Sistema <a class="header-anchor" href="#metricas-y-comportamiento-del-sistema" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; Métricas y Comportamiento del Sistema&quot;">​</a></h2><details class="details custom-block"><summary>P: La calidad gráfica disminuyó debido a los retrasos. ¡Ahora los FPS son altos de nuevo, pero los gráficos no se recuperan!</summary><p><strong>R:</strong> Es muy probable que se haya activado el <strong>Sistema de Penalización Anti Yo-Yo</strong>. El plugin bloqueó temporalmente las mejoras visuales para evitar la inestabilidad (Quality flickering).</p><ul><li>Si deseas que los gráficos se estabilicen más rápidamente, reduce el límite del parámetro <code>Penalty Lockout Duration</code> (por ejemplo, ajústalo a 10 segundos).</li><li>Revisa también el <code>Increase Cooldown</code>; podría tener un tiempo de espera demasiado alto.</li></ul></details><details class="details custom-block"><summary>P: El Dashboard indica de forma continua un Cuello de Botella de CPU (CPU Bottleneck) o Unknown, aunque la escena está vacía.</summary><p><strong>R:</strong> No olvides habilitar las <code>Frame Timing Stats</code> en Player Settings. Posteriormente, verifica si <code>Application.targetFrameRate = -1</code>. Al quitar los límites de la frecuencia de fotogramas, liberas y aíslas las métricas contra la desaceleración inducida por <code>setTimeout</code> del navegador.</p></details><details class="details custom-block"><summary>P: Mi personaje (o elementos físicos) tartamudea o da tirones (&quot;lags&quot;) fuertes.</summary><p><strong>R:</strong> Esto es un resultado colateral debido a la activación forzada del <code>Physics Step Scaler</code>. Este modula la base de <code>Time.fixedDeltaTime</code> para evitar bloqueos en la CPU ante sobrecargas drásticas de rendimiento. Asegura transiciones puramente fluidas activando inmediatamente el modo de <code>Interpolate</code> (o Extrapolate) que reside en la pestaña del componente <code>Rigidbody</code> del personaje.</p></details><details class="details custom-block"><summary>P: Los Shadow Scalers (Sombras) están activados, pero el rendimiento sigue disminuyendo y las sombras permanecen intactas.</summary><p><strong>R:</strong> Estos módulos monitorean y operan únicamente sobre las luces y sombras dinámicas en tiempo real. Si la &quot;iluminación en el mapa está precalculada (Baked/Lightmaps)&quot;, el plugin no tendrá ningún efecto sobre ella.</p></details><h2 id="scalers-personalizados" tabindex="-1"><i class="ph ph-code"></i> Scalers Personalizados <a class="header-anchor" href="#scalers-personalizados" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; Scalers Personalizados&quot;">​</a></h2><details class="details custom-block"><summary>P: ¡Mi propio Scaler funciona de manera excelente en el modo Editor, pero en la compilación de WebGL simplemente desaparece!</summary><p><strong>R:</strong> En los procedimientos internos normales, el integrador de arquitectura IL2CPP aniquila ese código asumiendo que es código sin usar (&quot;dead code&quot;). Procede con la inclusión obligatoria a través del atributo <code>[UnityEngine.Scripting.Preserve]</code> en la parte superior, encabezando la clase principal del Custom Scaler que creaste.</p></details>',16)])])}const g=a(t,[["render",l]]);export{p as __pageData,g as default};
